// Traditional approach (need to close in finally)
BufferedReader br = null;
// Code that may throw an exception
try {
    br = new BufferedReader(new FileReader("data.txt"));
    // Variable declaration and initialization
    String line = br.readLine();
    System.out.println(line);
} catch (IOException e) {
    e.printStackTrace();
} finally {
    // Conditional branch
    if (br != null) {
        // Code that may throw an exception
        try { br.close(); } catch (IOException e) { /* ignore */ }
    }
}

// try-with-resources (Java 7+): Automatic close
// Code that may throw an exception
try (BufferedReader br2 = new BufferedReader(new FileReader("data.txt"))) {
    String line = br2.readLine();
    System.out.println(line);
} catch (IOException e) {
    e.printStackTrace();
}
// br2 is automatically closed (no finally block needed)

// For multiple resources
