// Choosing between checked and unchecked exceptions:
//
// Checked exception (extends Exception):
//  → When the caller must handle it
//  → e.g., File not found, network error, insufficient balance
//
// Unchecked exception (extends RuntimeException):
//  → When indicating a program bug or invalid argument
//  → e.g., Non-existent ID specified, invalid state transition

// Exception chaining: Wrap a low-level exception in a high-level exception
public class DataAccessException extends RuntimeException {
    public DataAccessException(String message, Throwable cause) {
        super(message, cause);
    }
}

// Convert a low-level DB exception into an app-specific exception
public User findUser(int id) {
    try {
        // DB operation
        return userDao.findById(id);
    } catch (SQLException e) {
        // Wrap SQLException in DataAccessException
        throw new DataAccessException("User retrieval error: ID=" + id, e);
    }
}

// Caller side
try {
    User user = findUser(1);
} catch (DataAccessException e) {
    System.out.println(e.getMessage());       // "User retrieval error: ID=1"
    System.out.println(e.getCause());          // java.sql.SQLException: ...
    e.printStackTrace(); // Both stack traces are displayed
}

