// BAD 1: Swallowing exceptions (most dangerous)
try {
    riskyOperation();
} catch (Exception e) {
    // Doing nothing → can't tell what happened!
}

// BAD 2: Catching with broad Exception
try {
    int n = Integer.parseInt(input);
    File f = new File(path);
} catch (Exception e) {
    // Can't distinguish which exception occurred
    System.out.println("Error");
}

// BAD 3: Catch with only printStackTrace
try {
    readFile("data.txt");
} catch (IOException e) {
    e.printStackTrace(); // Logs appear but no actual handling
}

// BAD 4: Using exceptions for control flow
try {
    while (true) {
        array[i++] = 0; // Exception on out of bounds → exits loop
    }
} catch (ArrayIndexOutOfBoundsException e) {
    // This should be written with a for loop!
}

// BAD 5: return in finally
try {
    return computeValue();
} finally {
    return defaultValue; // Overrides the try return value
}

// GOOD 1: Catch specific exceptions and handle appropriately
// Code that may throw an exception
try {
    // Variable declaration and initialization
    int num = Integer.parseInt(input);
} catch (NumberFormatException e) {
    System.out.println("Please enter a number: " + input);
    num = 0; // Continue with a default value
}

// GOOD 2: Log and re-throw
// Code that may throw an exception
try {
    connection = getConnection();
} catch (SQLException e) {
    logger.error("DB connection error", e); // Log details
    // Throw an exception
    throw new DataAccessException("DB connection failed", e); // Re-throw with exception chaining
}

// GOOD 3: Use try-with-resources for resource management
// Code that may throw an exception
try (var reader = new BufferedReader(new FileReader(path))) {
    return reader.readLine();
} // Automatic close

