// Definition of the UserValidator class
public class UserValidator {

    // Definition of the validate method
    public static void validate(String name, int age, String email) {
        // Individual checks → specific messages
        // Conditional branch
        if (name == null || name.isBlank()) {
            // Throw an exception
            throw new IllegalArgumentException("Name is required");
        }
        if (name.length() > 50) {
            // Throw an exception
            throw new IllegalArgumentException(
                "Name must be 50 characters or less (input: " + name.length() + " characters)");
        }
        if (age < 0 || age > 150) {
            // Throw an exception
            throw new IllegalArgumentException(
                "Age must be between 0 and 150 (input: " + age + ")");
        }
        if (!email.contains("@")) {
            // Throw an exception
            throw new IllegalArgumentException(
                "Invalid email format: " + email);
        }
    }
}

// Caller side
// Code that may throw an exception
try {
    UserValidator.validate(name, age, email);
    userService.register(name, age, email);
    System.out.println("Registration complete");
} catch (IllegalArgumentException e) {
    System.out.println("Input error: " + e.getMessage());
}

// Definition of the fetchWithRetry method
public static String fetchWithRetry(String url, int maxRetries) {
    Exception lastException = null;

    // Loop (for statement)
    for (int attempt = 1; attempt <= maxRetries; attempt++) {
        // Code that may throw an exception
        try {
            HttpClient client = HttpClient.newHttpClient();
            HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(url)).build();
            HttpResponse<String> resp = client.send(
                req, HttpResponse.BodyHandlers.ofString());
            return resp.body(); // Success
        } catch (IOException | InterruptedException e) {
            lastException = e;
            System.out.printf("Retry %d/%d: %s%n",
                attempt, maxRetries, e.getMessage());
            // Code that may throw an exception
            try {
                Thread.sleep(1000L * attempt); // Gradually increase wait time
            } catch (InterruptedException ie) {
                Thread.currentThread().interrupt();
                // Throw an exception
                throw new RuntimeException("Retry interrupted", ie);
            }
        }
    }
    // Throw an exception
    throw new RuntimeException(
        "Failed after " + maxRetries + " retries", lastException);
}

